#!/usr/bin/env node
// Build-time copier for the Master Config handout. public/ is gitignored
// build output (regenerated by `rm -rf public && mv out public`), so the
// canonical docs live in the committed content/master-config/ and are
// copied into public/master-config/ on every build, making them
// downloadable at /master-config/*.md. Mirrors build-search-index.mjs,
// which likewise emits a static asset into public/ after the export.

import { readdirSync, copyFileSync, mkdirSync, existsSync, statSync } from "node:fs";
import { join } from "node:path";

const ROOT = process.cwd();
const SRC = join(ROOT, "content", "master-config");
const DEST = join(ROOT, "public", "master-config");

if (!existsSync(SRC)) {
  console.error(`[master-config] source dir not found at ${SRC}`);
  process.exit(1);
}
if (!existsSync(DEST)) mkdirSync(DEST, { recursive: true });

const files = readdirSync(SRC).filter((f) => f.endsWith(".md"));
let bytes = 0;
for (const f of files) {
  copyFileSync(join(SRC, f), join(DEST, f));
  bytes += statSync(join(DEST, f)).size;
}
console.log(
  `[master-config] copied ${files.length} docs to ${DEST} (${(bytes / 1024).toFixed(1)}KB)`,
);
